import{_ as l}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as s,c as p,f as n,q as i,D as t,N as d,g as o}from"./chunks/runtime-core.esm-bundler.DuRo-bNR.js";const C=JSON.parse('{"title":"阿里云安全组和服务器防火墙，到底有什么区别？","description":"","frontmatter":{},"headers":[],"relativePath":"column/Aliyun/核心概念/阿里云安全组和服务器防火墙.md","filePath":"column/Aliyun/核心概念/阿里云安全组和服务器防火墙.md","lastUpdated":1782182011000}'),r={name:"column/Aliyun/核心概念/阿里云安全组和服务器防火墙.md"};function h(c,a,u,b,k,g){const e=s("ArticleMetadata");return n(),p("div",null,[a[0]||(a[0]=i("h1",{id:"阿里云安全组和服务器防火墙-到底有什么区别",tabindex:"-1"},[o("阿里云安全组和服务器防火墙，到底有什么区别？ "),i("a",{class:"header-anchor",href:"#阿里云安全组和服务器防火墙-到底有什么区别","aria-label":'Permalink to "阿里云安全组和服务器防火墙，到底有什么区别？"'},"​")],-1)),t(e),a[1]||(a[1]=d('<p>很多人第一次把项目部署到阿里云 ECS 时，都会遇到一个非常典型的问题：</p><p>服务器里 <code>curl 127.0.0.1:82</code> 能通，<code>nginx</code> 也正常，容器也启动了，但浏览器访问 <code>http://公网IP:82</code> 就是打不开。</p><p>这时候，大概率不是代码有问题，而是你卡在了两个“门”上：</p><ol><li>阿里云安全组</li><li>服务器防火墙</li></ol><p>它们名字听起来都像“防火墙”，所以很容易混淆。实际上，这两个东西不在同一层，职责也不同。理解它们之后，服务器网络问题会清晰很多。</p><h2 id="一句话先讲明白" tabindex="-1">一句话先讲明白 <a class="header-anchor" href="#一句话先讲明白" aria-label="Permalink to &quot;一句话先讲明白&quot;">​</a></h2><p>阿里云安全组，是云平台层面的第一道门。</p><p>服务器防火墙，是操作系统层面的第二道门。</p><p>外部请求想访问你的服务，通常要先过阿里云安全组，再过服务器防火墙，最后才能到你的 <code>nginx</code>、Docker 容器或者应用进程。</p><p>也就是说：</p><p><strong>只开安全组不行，只开服务器防火墙也不行。</strong></p><p>两边都放行，外部访问才真正能通。</p><h2 id="可以把它理解成两道门禁" tabindex="-1">可以把它理解成两道门禁 <a class="header-anchor" href="#可以把它理解成两道门禁" aria-label="Permalink to &quot;可以把它理解成两道门禁&quot;">​</a></h2><p>假设你的服务器是一栋楼。</p><ul><li>阿里云安全组，是小区大门</li><li>服务器防火墙，是你家门口的防盗门</li><li><code>nginx</code>、Docker、应用服务，是屋里的具体房间</li></ul><p>一个访客从外面来找你，流程是这样的：</p><p><code>互联网 -&gt; 阿里云安全组 -&gt; ECS 网卡 -&gt; 服务器防火墙 -&gt; Nginx / Docker / 应用</code></p><p>任何一层没放行，请求都会失败。</p><h2 id="阿里云安全组是什么" tabindex="-1">阿里云安全组是什么 <a class="header-anchor" href="#阿里云安全组是什么" aria-label="Permalink to &quot;阿里云安全组是什么&quot;">​</a></h2><p>阿里云安全组，是 ECS 实例外围的网络访问控制规则。你可以理解成云服务器的“云端门禁”。</p><p>它控制的是：</p><ul><li>哪些端口允许外部访问</li><li>哪些来源 IP 可以访问</li><li>哪些协议可以通过，比如 TCP、UDP</li><li>出方向和入方向是否允许通信</li></ul><p>比如你的网站跑在 <code>82</code> 端口，如果阿里云安全组没有开放 <code>82/tcp</code>，那外部请求根本到不了你的服务器系统。</p><p>这时候你在服务器里执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:82</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>可能是通的。</p><p>但你在自己电脑浏览器里访问：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http://47.101.33.206:82</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>却不通。</p><p>原因就是：请求还没到服务器，就已经被阿里云安全组拦住了。</p><h2 id="服务器防火墙是什么" tabindex="-1">服务器防火墙是什么 <a class="header-anchor" href="#服务器防火墙是什么" aria-label="Permalink to &quot;服务器防火墙是什么&quot;">​</a></h2><p>服务器防火墙，是 ECS 操作系统内部的网络控制机制。</p><p>常见的有：</p><ul><li><code>firewalld</code></li><li><code>iptables</code></li><li><code>nftables</code></li></ul><p>在 CentOS、Alibaba Cloud Linux、RHEL 这类系统里，很多时候你会接触到的是 <code>firewalld</code>。</p><p>它控制的是：</p><ul><li>服务器本机允许哪些端口被访问</li><li>哪些服务可以对外监听</li><li>哪些来源可以进入系统</li></ul><p>如果阿里云安全组已经开放了 <code>82</code> 端口，但系统防火墙没开放，那么请求虽然已经到达 ECS 机器，但会被系统内部挡住。</p><p>这种情况下，你可能会看到：</p><ul><li>安全组配置没问题</li><li><code>nginx</code> 在监听 <code>82</code></li><li>但浏览器还是连不上</li></ul><p>这就说明，请求到了云服务器边缘，但没穿过系统这层门。</p><h2 id="两者最核心的区别" tabindex="-1">两者最核心的区别 <a class="header-anchor" href="#两者最核心的区别" aria-label="Permalink to &quot;两者最核心的区别&quot;">​</a></h2><p>最简单的区别如下：</p><h3 id="_1-所在位置不同" tabindex="-1">1. 所在位置不同 <a class="header-anchor" href="#_1-所在位置不同" aria-label="Permalink to &quot;1. 所在位置不同&quot;">​</a></h3><ul><li>阿里云安全组：云平台层</li><li>服务器防火墙：操作系统层</li></ul><h3 id="_2-生效范围不同" tabindex="-1">2. 生效范围不同 <a class="header-anchor" href="#_2-生效范围不同" aria-label="Permalink to &quot;2. 生效范围不同&quot;">​</a></h3><ul><li>阿里云安全组：控制 ECS 实例对外的网络访问</li><li>服务器防火墙：控制这台 Linux 系统自身的网络访问</li></ul><h3 id="_3-排错位置不同" tabindex="-1">3. 排错位置不同 <a class="header-anchor" href="#_3-排错位置不同" aria-label="Permalink to &quot;3. 排错位置不同&quot;">​</a></h3><ul><li>安全组没开：请求根本到不了服务器</li><li>防火墙没开：请求到了服务器，但进不了系统服务</li></ul><h3 id="_4-配置方式不同" tabindex="-1">4. 配置方式不同 <a class="header-anchor" href="#_4-配置方式不同" aria-label="Permalink to &quot;4. 配置方式不同&quot;">​</a></h3><ul><li>安全组：在阿里云控制台配置</li><li>防火墙：在服务器终端执行命令配置</li></ul><h2 id="为什么很多人会误判问题" tabindex="-1">为什么很多人会误判问题 <a class="header-anchor" href="#为什么很多人会误判问题" aria-label="Permalink to &quot;为什么很多人会误判问题&quot;">​</a></h2><p>因为部署成功后，最容易做的测试是本机测试。</p><p>比如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:82</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果返回了 HTML，大家就会觉得“服务没问题”。</p><p>这个判断只对了一半。</p><p>它只能证明：</p><ul><li><code>nginx</code> 在工作</li><li>应用在工作</li><li>服务器本机回环访问没问题</li></ul><p>它不能证明：</p><ul><li>公网是否能访问</li><li>安全组是否放行</li><li>防火墙是否放行</li></ul><p>所以“本机 curl 通了”不等于“公网能访问”。</p><h2 id="一个最常见的部署场景" tabindex="-1">一个最常见的部署场景 <a class="header-anchor" href="#一个最常见的部署场景" aria-label="Permalink to &quot;一个最常见的部署场景&quot;">​</a></h2><p>假设你把项目部署在阿里云 ECS 上，结构是这样的：</p><ul><li>宿主机 <code>nginx</code> 监听 <code>82</code></li><li>宿主机 <code>nginx</code> 反向代理到 <code>127.0.0.1:8001</code></li><li>Docker 里的 <code>web</code> 容器映射到宿主机 <code>8001</code></li><li>前端再通过 <code>/api/v1</code> 访问后端</li></ul><p>这时公网访问路径是：</p><p><code>浏览器 -&gt; 公网IP:82 -&gt; 阿里云安全组 -&gt; 服务器防火墙 -&gt; 宿主机 Nginx:82 -&gt; 127.0.0.1:8001 -&gt; Docker web 容器</code></p><p>这里任何一个环节错了，网站都打不开。</p><h2 id="怎么判断问题出在哪一层" tabindex="-1">怎么判断问题出在哪一层 <a class="header-anchor" href="#怎么判断问题出在哪一层" aria-label="Permalink to &quot;怎么判断问题出在哪一层&quot;">​</a></h2><p>我建议按下面顺序查。</p><h2 id="第一步-看服务是不是已经监听端口" tabindex="-1">第一步：看服务是不是已经监听端口 <a class="header-anchor" href="#第一步-看服务是不是已经监听端口" aria-label="Permalink to &quot;第一步：看服务是不是已经监听端口&quot;">​</a></h2><p>先确认 <code>nginx</code> 或你的应用是否真的在监听：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :82</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果能看到类似：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">LISTEN</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 511</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0.0.0.0:82</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>说明宿主机上确实有进程在监听 <code>82</code> 端口。</p><p>如果这里没有监听，先别看安全组和防火墙，先修服务本身。</p><h2 id="第二步-看服务器本机能不能访问" tabindex="-1">第二步：看服务器本机能不能访问 <a class="header-anchor" href="#第二步-看服务器本机能不能访问" aria-label="Permalink to &quot;第二步：看服务器本机能不能访问&quot;">​</a></h2><p>执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:82</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果返回页面 HTML，说明本机访问没问题。</p><p>如果这里都不通，那问题在：</p><ul><li><code>nginx</code> 配置</li><li>Docker 端口映射</li><li>容器没启动</li><li>应用没启动</li></ul><p>这时还不需要查安全组。</p><h2 id="第三步-看服务器防火墙有没有开放端口" tabindex="-1">第三步：看服务器防火墙有没有开放端口 <a class="header-anchor" href="#第三步-看服务器防火墙有没有开放端口" aria-label="Permalink to &quot;第三步：看服务器防火墙有没有开放端口&quot;">​</a></h2><p>如果你用的是 <code>firewalld</code>，先看已开放端口：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">firewall-cmd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list-ports</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果没有 <code>82/tcp</code>，那就需要开放：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">firewall-cmd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --permanent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --add-port=82/tcp</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">firewall-cmd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reload</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">firewall-cmd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list-ports</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>看到结果里有：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">82/tcp</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>才算系统层放通了。</p><p>如果你的系统没启用 <code>firewalld</code>，也可能需要检查 <code>iptables</code> 或 <code>nftables</code> 规则。</p><h2 id="第四步-看阿里云安全组有没有开放端口" tabindex="-1">第四步：看阿里云安全组有没有开放端口 <a class="header-anchor" href="#第四步-看阿里云安全组有没有开放端口" aria-label="Permalink to &quot;第四步：看阿里云安全组有没有开放端口&quot;">​</a></h2><p>登录阿里云控制台，找到这台 ECS 对应的安全组。</p><p>检查入方向规则里是否有：</p><ul><li>协议类型：TCP</li><li>端口范围：82/82</li><li>授权对象：<code>0.0.0.0/0</code></li></ul><p>如果没有，就新增一条。</p><p>这一步非常关键。很多人服务器里全通了，但控制台安全组没放行，结果公网就是不通。</p><h2 id="第五步-从外部机器访问" tabindex="-1">第五步：从外部机器访问 <a class="header-anchor" href="#第五步-从外部机器访问" aria-label="Permalink to &quot;第五步：从外部机器访问&quot;">​</a></h2><p>最后，用你自己的电脑浏览器打开：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http://你的公网IP:82</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者用本地命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://你的公网IP:82</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果这里能通，说明整条链路已经打通。</p><h2 id="一个很重要的结论" tabindex="-1">一个很重要的结论 <a class="header-anchor" href="#一个很重要的结论" aria-label="Permalink to &quot;一个很重要的结论&quot;">​</a></h2><p><strong>外网访问问题，必须分层排查。</strong></p><p>不要一上来就改代码，也不要一上来就怀疑 Docker。</p><p>先确认：</p><ol><li>服务有没有监听</li><li>本机能不能访问</li><li>防火墙有没有放行</li><li>安全组有没有放行</li><li>外部机器能不能连通</li></ol><p>按这个顺序查，效率最高。</p><h2 id="安全组和防火墙能不能只留一个" tabindex="-1">安全组和防火墙能不能只留一个 <a class="header-anchor" href="#安全组和防火墙能不能只留一个" aria-label="Permalink to &quot;安全组和防火墙能不能只留一个&quot;">​</a></h2><p>理论上，某些场景下你可以让系统防火墙关闭，只依赖阿里云安全组。</p><p>也可以让安全组放得比较宽，再依赖系统防火墙细控。</p><p>但对于大多数个人开发者和中小项目来说，我更建议：</p><p><strong>两边都保留，并且规则明确。</strong></p><p>原因很简单：</p><ul><li>安全组负责云侧入口控制</li><li>防火墙负责系统内部第二层保护</li><li>双层控制更稳，排障也更清晰</li></ul><p>当然，规则不要乱配。最怕的是两边都配了，但自己都不知道放了什么、挡了什么。</p><h2 id="实际部署时应该怎么配" tabindex="-1">实际部署时应该怎么配 <a class="header-anchor" href="#实际部署时应该怎么配" aria-label="Permalink to &quot;实际部署时应该怎么配&quot;">​</a></h2><p>如果你只是部署一个普通 Web 项目，常见做法是这样：</p><h3 id="阿里云安全组开放" tabindex="-1">阿里云安全组开放 <a class="header-anchor" href="#阿里云安全组开放" aria-label="Permalink to &quot;阿里云安全组开放&quot;">​</a></h3><ul><li><code>22/tcp</code>：SSH 登录</li><li><code>80/tcp</code>：HTTP</li><li><code>443/tcp</code>：HTTPS</li><li><code>82/tcp</code>：你当前项目临时使用的访问端口</li></ul><h3 id="服务器防火墙开放" tabindex="-1">服务器防火墙开放 <a class="header-anchor" href="#服务器防火墙开放" aria-label="Permalink to &quot;服务器防火墙开放&quot;">​</a></h3><ul><li><code>22/tcp</code></li><li><code>80/tcp</code></li><li><code>443/tcp</code></li><li><code>82/tcp</code></li></ul><h3 id="不建议开放的端口" tabindex="-1">不建议开放的端口 <a class="header-anchor" href="#不建议开放的端口" aria-label="Permalink to &quot;不建议开放的端口&quot;">​</a></h3><p>除非你明确知道自己在做什么，否则不要把这些内部端口直接暴露公网：</p><ul><li><code>3301</code> 后端 API 端口</li><li><code>6379</code> Redis 端口</li><li>数据库端口，比如 <code>5432</code>、<code>3306</code></li></ul><p>这些端口更适合只在内网或 Docker 网络里通信，不应该直接给公网访问。</p><h2 id="docker-场景下为什么更容易绕晕" tabindex="-1">Docker 场景下为什么更容易绕晕 <a class="header-anchor" href="#docker-场景下为什么更容易绕晕" aria-label="Permalink to &quot;Docker 场景下为什么更容易绕晕&quot;">​</a></h2><p>因为 Docker 又引入了一层端口映射。</p><p>例如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">127.0.0.1:8001</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 容器</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这意味着：</p><ul><li>容器内服务监听的是 <code>80</code></li><li>宿主机暴露的是 <code>8001</code></li><li>外网访问不一定直接访问 <code>8001</code></li><li>你可能还会再通过宿主机 <code>nginx:82</code> 转发到 <code>8001</code></li></ul><p>这时候你会同时看到：</p><ul><li>容器端口</li><li>宿主机端口</li><li>Nginx 监听端口</li><li>公网开放端口</li></ul><p>如果脑子里没有“分层”概念，很容易把它们混成一团。</p><p>正确理解应该是：</p><ul><li>容器端口，是容器内部服务端口</li><li>宿主机端口，是 Docker 映射出来给宿主机用的</li><li>Nginx 监听端口，是外部真正访问的入口</li><li>安全组和防火墙，控制的是外部请求能不能走到这个入口</li></ul><h2 id="我个人推荐的排障方法" tabindex="-1">我个人推荐的排障方法 <a class="header-anchor" href="#我个人推荐的排障方法" aria-label="Permalink to &quot;我个人推荐的排障方法&quot;">​</a></h2><p>以后遇到“浏览器打不开”的情况，直接按这 6 条查：</p><ol><li><code>docker compose ps</code> 看容器是不是正常启动</li><li><code>ss -lntp</code> 看宿主机端口有没有监听</li><li><code>curl 127.0.0.1:端口</code> 看本机是否能通</li><li><code>nginx -t</code> 看反向代理配置是否正确</li><li><code>firewall-cmd --list-ports</code> 看系统防火墙是否放行</li><li>去阿里云控制台看安全组是否放行</li></ol><p>只要这 6 步按顺序做，绝大多数网络访问问题都能定位出来。</p><h2 id="新手最容易踩的几个坑" tabindex="-1">新手最容易踩的几个坑 <a class="header-anchor" href="#新手最容易踩的几个坑" aria-label="Permalink to &quot;新手最容易踩的几个坑&quot;">​</a></h2><h3 id="_1-以为容器启动了-公网就一定能访问" tabindex="-1">1. 以为容器启动了，公网就一定能访问 <a class="header-anchor" href="#_1-以为容器启动了-公网就一定能访问" aria-label="Permalink to &quot;1. 以为容器启动了，公网就一定能访问&quot;">​</a></h3><p>不对。容器启动只能说明应用活着，不代表外网链路通了。</p><h3 id="_2-以为-curl-127-0-0-1-通了就万事大吉" tabindex="-1">2. 以为 <code>curl 127.0.0.1</code> 通了就万事大吉 <a class="header-anchor" href="#_2-以为-curl-127-0-0-1-通了就万事大吉" aria-label="Permalink to &quot;2. 以为 `curl 127.0.0.1` 通了就万事大吉&quot;">​</a></h3><p>不对。这只能证明本机回环通，不代表公网通。</p><h3 id="_3-只改安全组-不改服务器防火墙" tabindex="-1">3. 只改安全组，不改服务器防火墙 <a class="header-anchor" href="#_3-只改安全组-不改服务器防火墙" aria-label="Permalink to &quot;3. 只改安全组，不改服务器防火墙&quot;">​</a></h3><p>不够。系统层还可能挡住。</p><h3 id="_4-只改服务器防火墙-不改安全组" tabindex="-1">4. 只改服务器防火墙，不改安全组 <a class="header-anchor" href="#_4-只改服务器防火墙-不改安全组" aria-label="Permalink to &quot;4. 只改服务器防火墙，不改安全组&quot;">​</a></h3><p>也不够。云平台层可能直接拦截。</p><h3 id="_5-把-redis、数据库直接暴露到公网" tabindex="-1">5. 把 Redis、数据库直接暴露到公网 <a class="header-anchor" href="#_5-把-redis、数据库直接暴露到公网" aria-label="Permalink to &quot;5. 把 Redis、数据库直接暴露到公网&quot;">​</a></h3><p>很危险。内部依赖尽量只在内网使用，不要图省事直接对外开放。</p><h2 id="最后总结" tabindex="-1">最后总结 <a class="header-anchor" href="#最后总结" aria-label="Permalink to &quot;最后总结&quot;">​</a></h2><p>阿里云安全组和服务器防火墙，不是二选一，而是两层不同位置的访问控制。</p><p>你可以把它记成一句话：</p><p><strong>安全组管“能不能到服务器”，防火墙管“到了服务器能不能进系统服务”。</strong></p><p>所以当你的网站打不开时，不要只盯着代码和 Docker，先把整条访问链路想清楚：</p><p><code>公网 -&gt; 安全组 -&gt; 服务器防火墙 -&gt; Nginx -&gt; Docker -&gt; 应用</code></p><p>只要你学会按层排查，部署问题会简单很多。</p>',162))])}const F=l(r,[["render",h]]);export{C as __pageData,F as default};
